SELECT o.orderid, o.shippeddate, o.shipregion, c.categoryname, p.productname, od.quantity, od.unitprice, (od.quantity * od.unitprice) AS line_item_revenue FROM orders AS o JOIN "order details" AS od ON o.orderid = od.orderid JOIN products AS p ON od.productid = p.productid JOIN categories AS c ON p.categoryid = c.categoryid LEFT JOIN region AS r ON o.shipregion = r.regionid WHERE (c.categoryname = 'Confections') AND (r.regiondescription = 'Eastern' OR r.regiondescription IS NULL) AND (strftime('%Y', o.shippeddate) = '1997')
